const body = $input.first().json.body || $input.first().json;

// ElevenLabs post-call payload structure
const conversationId = body.conversation_id || '';
const agentId = body.agent_id || '';
const status = body.status || '';
const transcript = body.transcript || '';
const recordingUrl = body.recording_url || '';
const durationSeconds = body.duration_seconds || 0;

// Data collection fields from ElevenLabs agent
const dataFields = body.data_collection || body.analysis?.data_collection || {};

// Structured fields Adam collected
const callOutcome = dataFields.call_outcome?.value || 'no_answer';
const prospectSummary = dataFields.prospect_summary?.value || '';
const callbackTime = dataFields.callback_requested_time?.value || '';
const disqualReason = dataFields.disqualification_reason?.value || '';

// New rescore fields
const companySizeRaw = dataFields.company_size?.value;
const companySize = parseInt(companySizeRaw) || 0;
const revenueRange = dataFields.revenue_range?.value || '';
const prospectRole = dataFields.prospect_role?.value || '';

// Phone number from dynamic variables (ElevenLabs echoes these back)
const dynamicVars = body.conversation_initiation_client_data?.dynamic_variables || {};
const customerName = dynamicVars.customer_name || '';

// Map revenue_range enum to score
const revenueScores = {
  'over_100m': 25,
  '25m_100m': 25,
  '5m_25m': 20,
  '1m_5m': 15,
  'under_1m': 3
};
const revenuePts = revenueScores[revenueRange] || 0;

// Map role to score
const roleScores = {
  'Owner / C-Suite': 20,
  'VP / Director': 15,
  'Manager': 8,
  'Individual Contributor': 3
};
const rolePts = roleScores[prospectRole] || 0;

// Employee score
let empPts = 0;
if (companySize >= 10 && companySize <= 150) empPts = 15;
else if (companySize > 150) empPts = 10;
else if (companySize > 0) empPts = 5;

// Lead tier
const isGrowth = (companySize >= 10 && companySize <= 150) ||
  ['5m_25m','25m_100m','over_100m'].includes(revenueRange);
const leadTier = isGrowth ? 'growth' : 'starter';

// Rescore total (hard fields only — no message score needed post-call)
const rescoreTotal = revenuePts + rolePts + empPts;

// Bucket based on rescore (these fields replace form data)
let bucket = 'cold';
if (rescoreTotal >= 35) bucket = 'hot';
else if (rescoreTotal >= 20) bucket = 'warm';

// Override bucket based on call outcome
// If they booked or requested callback, treat as hot regardless of score
if (['booked', 'callback_requested'].includes(callOutcome)) bucket = 'hot';
if (callOutcome === 'not_interested' || callOutcome === 'disqualified') bucket = 'cold';

return [{
  json: {
    conversationId,
    agentId,
    status,
    recordingUrl,
    durationSeconds,
    transcript,
    callOutcome,
    prospectSummary,
    callbackTime,
    disqualReason,
    companySize,
    revenueRange,
    prospectRole,
    revenuePts,
    rolePts,
    empPts,
    rescoreTotal,
    bucket,
    leadTier,
    rescoreBreakdown: `Post-call rescore: Revenue +${revenuePts} | Role +${rolePts} | Employees +${empPts} = ${rescoreTotal}pts → ${bucket.toUpperCase()} | Outcome: ${callOutcome}`
  }
}];

